import{_ as e,o as a,c as i,ag as r}from"./chunks/framework.CvgP6Fyv.js";const g=JSON.parse('{"title":"Contracts","description":"","frontmatter":{},"headers":[],"relativePath":"features/contracts.md","filePath":"features/contracts.md"}'),n={name:"features/contracts.md"};function o(s,t,c,l,u,h){return a(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="contracts" tabindex="-1">Contracts <a class="header-anchor" href="#contracts" aria-label="Permalink to &quot;Contracts&quot;">​</a></h1><p>Manage recurring service agreements and rental contracts with automatic billing schedules.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Contracts represent ongoing agreements with customers — such as monthly service contracts, rental agreements, or maintenance plans. They can generate invoices automatically on a set schedule.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>The contracts module is optional. Enable it in <strong>Company &gt; Features</strong> if you don&#39;t see it in the navigation.</p></div><h2 id="creating-a-contract" tabindex="-1">Creating a contract <a class="header-anchor" href="#creating-a-contract" aria-label="Permalink to &quot;Creating a contract&quot;">​</a></h2><ol><li>Go to <strong>Contracts &gt; New Contract</strong></li><li>Fill in: <ul><li><strong>Name</strong> — A descriptive title (e.g., &quot;Monthly cleaning service&quot;)</li><li><strong>Customer</strong> — The client party to the contract</li><li><strong>Amount</strong> — The recurring billing amount</li><li><strong>Recurrence</strong> — How often to bill (weekly, monthly, quarterly, yearly)</li><li><strong>Start date</strong> — When the contract begins</li><li><strong>End date</strong> — Optional end date</li><li><strong>Description</strong> — Terms and details</li></ul></li><li>Click <strong>Save</strong></li></ol><h2 id="contract-statuses" tabindex="-1">Contract statuses <a class="header-anchor" href="#contract-statuses" aria-label="Permalink to &quot;Contract statuses&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Status</th><th>Description</th></tr></thead><tbody><tr><td><strong>Active</strong></td><td>Currently in effect, generates invoices</td></tr><tr><td><strong>Inactive</strong></td><td>Paused — no invoices generated</td></tr></tbody></table><h2 id="automatic-invoicing" tabindex="-1">Automatic invoicing <a class="header-anchor" href="#automatic-invoicing" aria-label="Permalink to &quot;Automatic invoicing&quot;">​</a></h2><p>Active contracts with a recurrence schedule automatically generate invoices at each billing period. The system:</p><ol><li>Creates a draft invoice based on the contract terms</li><li>Applies the correct customer, amount, and description</li><li>Follows your invoice numbering settings</li></ol><p>You can review and send generated invoices manually, or configure auto-sending.</p><h2 id="linking-to-assets" tabindex="-1">Linking to assets <a class="header-anchor" href="#linking-to-assets" aria-label="Permalink to &quot;Linking to assets&quot;">​</a></h2><p>Contracts can be linked to <a href="/features/objects">objects/assets</a> for rental management:</p><ul><li>Associate a contract with a property, vehicle, or piece of equipment</li><li>Track which assets are currently rented and to whom</li><li>View contract history per asset</li></ul><h2 id="metrics" tabindex="-1">Metrics <a class="header-anchor" href="#metrics" aria-label="Permalink to &quot;Metrics&quot;">​</a></h2><p>The contracts list page shows summary metrics:</p><ul><li>Total active contracts</li><li>Total contract value</li><li>Contracts by recurrence type</li></ul><h2 id="bulk-actions" tabindex="-1">Bulk actions <a class="header-anchor" href="#bulk-actions" aria-label="Permalink to &quot;Bulk actions&quot;">​</a></h2><ul><li><strong>Change status</strong> — Activate or deactivate multiple contracts</li><li><strong>Archive</strong> — Move to archive</li><li><strong>Restore</strong> — Bring back archived contracts</li></ul><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Use contracts together with <a href="/features/recurring-invoices">recurring invoices</a> for different billing scenarios</li><li>Link contracts to objects for full rental management</li><li>Set end dates to get notified before contracts expire</li><li>Review the contracts filter to see active vs. inactive at a glance</li></ul>',23)])])}const m=e(n,[["render",o]]);export{g as __pageData,m as default};
